    CGFloat itemHeight = ZOOMW(112);
    CGFloat itemGap = ZOOMW(10);
    NSInteger numberOfRows = (self.effectData.count + 1) / 2;
    CGFloat totalHeight = numberOfRows * itemHeight + MAX(numberOfRows - 1, 0) * itemGap;

    self.ToneView = [[UIView alloc] init];
    [self.view addSubview:self.ToneView];
    [self.ToneView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view).offset(ZOOMW(20));
        make.left.right.equalTo(self.view).inset(ZOOMW(16));
        make.height.mas_equalTo(totalHeight);
    }];

    NSMutableArray *tones = @[].mutableCopy;
    for (int i = 0; i < self.effectData.count; i++) {
        NSDictionary *item = self.effectData[i];

        ToneView *tone = [[ToneView alloc] init];
        tone.backgroundColor = RGBA(239, 246, 240, 1);
        tone.type = item[@"type"];
        tone.nameLabel.text = item[@"title"];
        tone.decribeLabel.text = item[@"description"];
        tone.icon.image = [UIImage imageNamed:item[@"image"]];
        tone.layer.cornerRadius = ZOOMW(16);

        __weak typeof(self) weakSelf = self;
        tone.onTapped = ^(ToneView *view) {
            [weakSelf toneSelected:view];
        };

        [self.ToneView addSubview:tone];
        [tones addObject:tone];
    }
    self.tones = tones;

    for (NSInteger i = 0; i < tones.count; i++) {
        ToneView *tone = tones[i];
        NSInteger column = i % 2;
        NSInteger row = i / 2;
        [tone mas_makeConstraints:^(MASConstraintMaker *make) {
            make.height.mas_equalTo(itemHeight);
            make.width.mas_equalTo(([UIScreen mainScreen].bounds.size.width - ZOOMW(32) - itemGap) / 2.0);
            if (column == 0) {
                make.left.equalTo(self.ToneView);
            } else {
                make.right.equalTo(self.ToneView);
            }
            if (row == 0) {
                make.top.equalTo(self.ToneView);
            } else {
                make.top.equalTo(((ToneView *)tones[i - 2]).mas_bottom).offset(itemGap);
            }
        }];
    }
}

