#pragma mark - Audio Control

- (void)playRecordedAudio {
    if (!self.recordFileURL || self.recorder.isRecording) {
        return;
    }

    if (!self.isPlaying) {
        [self stopPlayback];
        [self setupEngineForCurrentEffect];
        [self scheduleAudioFileForPlayback];
        [self.playerNode play];
        self.isPlaying = YES;
    } else {
        [self stopPlayback];
    }

    [self updatePlaybackControlState];
}

- (void)setupEngineForCurrentEffect {
    self.engine = [[AVAudioEngine alloc] init];
    self.playerNode = [[AVAudioPlayerNode alloc] init];
    self.pitchNode = [[AVAudioUnitTimePitch alloc] init];
    AVAudioUnitReverb *reverb = [[AVAudioUnitReverb alloc] init];

    self.pitchNode.pitch = 0;
    self.pitchNode.rate = 1.0;
    reverb.wetDryMix = 0;

    if ([self.selectedEffect isEqualToString:@"chipmunk"]) {
        self.pitchNode.pitch = 1000;
        self.pitchNode.rate = 1.2;
    } else if ([self.selectedEffect isEqualToString:@"deep"]) {
        self.pitchNode.pitch = -800;
        self.pitchNode.rate = 0.9;
    } else if ([self.selectedEffect isEqualToString:@"robot"]) {
        self.pitchNode.overlap = 8.0;
    } else if ([self.selectedEffect isEqualToString:@"girl"]) {
        self.pitchNode.pitch = 800;  // 适当提高音调模拟女声
        self.pitchNode.rate = 1.1;   // 稍微加快语速
        // 可以保留一些混响效果让声音更自然
        reverb.wetDryMix = 30;       // 降低混响强度
    }

    [self.engine attachNode:self.playerNode];
    [self.engine attachNode:self.pitchNode];
    [self.engine attachNode:reverb];
    [self.engine connect:self.playerNode to:self.pitchNode format:nil];
    [self.engine connect:self.pitchNode to:reverb format:nil];
    [self.engine connect:reverb to:self.engine.mainMixerNode format:nil];

    self.audioFile = [[AVAudioFile alloc] initForReading:self.recordFileURL error:nil];

    [self.engine prepare];
    [self.engine startAndReturnError:nil];
}

- (void)scheduleAudioFileForPlayback {
    if (!self.audioFile) return;

    __weak typeof(self) weakSelf = self;

    [self.playerNode stop];
    [self.playerNode scheduleFile:self.audioFile
                           atTime:nil
                completionHandler:^{
        dispatch_async(dispatch_get_main_queue(), ^{
            [weakSelf stopPlayback];
            [weakSelf updatePlaybackControlState];
        });
    }];
}

- (void)stopPlayback {
    [self.playerNode stop];
    [self.engine stop];
    self.playerNode = nil;
    self.engine = nil;
    self.pitchNode = nil;
    self.isPlaying = NO;
}

- (void)updateToneSelectionUI {
    UIColor *selectedColor = BUTTON_COLOR;
    for (ToneView *tone in self.tones) {
        BOOL isSelected = [tone.type isEqualToString:self.selectedEffect];
        tone.selectedButton.selected = isSelected;
        tone.selectedButton.backgroundColor = isSelected ? selectedColor : UIColor.clearColor;
        if (isSelected) {
            self.selectedView = tone;
        }
    }
}

- (void)updatePlaybackControlState {
    UIImage *playImage = [UIImage imageNamed:self.isPlaying ? @"A_pause" : @"A_play"];
    self.tipLabel.hidden = self.hasRecord;

    [self.playButton setImage:playImage forState:UIControlStateNormal];
    [self.playButton setImage:playImage forState:UIControlStateDisabled];
    self.playButton.enabled = self.hasRecord;
    self.playButton.backgroundColor = self.hasRecord ? BUTTON_COLOR : UIColor.whiteColor;
    self.playButton.layer.borderWidth = self.hasRecord ? 0 : 1;
    self.playButton.layer.borderColor = BUTTON_COLOR.CGColor;
}

#pragma mark - Audio Setup

- (void)setupAudioSession {
    AVAudioSession *session = [AVAudioSession sharedInstance];
    [session setCategory:AVAudioSessionCategoryPlayAndRecord
             withOptions:AVAudioSessionCategoryOptionDefaultToSpeaker
                   error:nil];
    [session setActive:YES error:nil];
}

#pragma mark - Record & Play

- (void)startRecording {
    [self stopPlayback];
    self.hasRecord = NO;
    [self updatePlaybackControlState];

    NSString *path = [NSTemporaryDirectory() stringByAppendingPathComponent:@"tempVoice.m4a"];
    self.recordFileURL = [NSURL fileURLWithPath:path];

    NSDictionary *settings = @{
        AVFormatIDKey: @(kAudioFormatMPEG4AAC),
        AVSampleRateKey: @44100.0,
        AVNumberOfChannelsKey: @1,
        AVEncoderAudioQualityKey: @(AVAudioQualityHigh)
    };

    self.recorder = [[AVAudioRecorder alloc] initWithURL:self.recordFileURL settings:settings error:nil];
    [self.recorder prepareToRecord];
    [self.recorder record];

    _recordButton.backgroundColor = [UIColor colorWithRed:255/255.0 green:100/255.0 blue:100/255.0 alpha:1.0];
    [_recordButton setTitle:@"Recording..." forState:UIControlStateNormal];

    NSLog(@"🎙 Start recording");
}

- (void)stopRecordingAndPlay {
    if (self.recorder.isRecording) {
        [self.recorder stop];
        self.hasRecord = YES;
        NSLog(@"✅ Recording finished");

        _recordButton.backgroundColor = BUTTON_COLOR;
        [_recordButton setTitle:@"Hold to Talk" forState:UIControlStateNormal];

        [self playWithEffect:self.selectedEffect];
        [self updatePlaybackControlState];
    }
}

#pragma mark - Voice Effect Playback

- (void)playWithEffect:(NSString *)effectType {
    if (!effectType.length || !self.recordFileURL) {
        return;
    }

    self.selectedEffect = effectType;
    [self stopPlayback];
    self.audioFile = [[AVAudioFile alloc] initForReading:self.recordFileURL error:nil];
    self.isPlaying = NO;
    [self updatePlaybackControlState];
}

@end

