}

- (instancetype)initWithTitle:(NSString *)title fontSize:(NSUInteger)fontSize bold:(BOOL)isBold height:(CGFloat)height titleColor:(UIColor * _Nullable)titleColor backGroundColor:(UIColor * _Nullable)backgroundColor {
    if (self = [self init]) {
        [self setTitle:title forState:UIControlStateNormal];
        self.titleLabel.font = isBold ? [UIFont fontWithName:@"PingFangSC-Semibold" size: fontSize] : [UIFont fontWithName:@"PingFang SC" size: fontSize];

